<div class="wp-block-group alignfull" style="padding-top:var(--wp--preset--spacing--65)"><!-- wp:columns -->
    <div class="wp-block-columns"><!-- wp:column {"width":"60%"} -->
        <div class="wp-block-column" style="flex-basis:60%"><!-- wp:buttons -->
